create.query:
#graphql
    mutation GiftCardCreate($input: GiftCardCreateInput!) {
      giftCardCreate(input: $input) {
        giftCard {
          #graphql
  id
  lastCharacters
  maskedCode
  enabled
  deactivatedAt
  expiresOn
  note
  templateSuffix
  createdAt
  updatedAt
  initialValue {
    amount
    currencyCode
  }
  balance {
    amount
    currencyCode
  }

        }
        giftCardCode
        userErrors {
          field
          message
        }
      }
    }

